import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class CommentWrappingRuleSingleLineBlockTest {
    private val commentWrappingRuleAssertThat = assertThatRule { CommentWrappingRule() }

    @Test
    fun `Given a single line lambda block containing only a block comment then do not report a lint violation`() {
        val code =
            """
            val foo = { /* no-op */ }
            """.trimIndent()
        commentWrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a single line function block containing only a block comment then do not report a lint violation`() {
        val code =
            """
            fun foo() { /* no-op */ }
            """.trimIndent()
        commentWrappingRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

